"use client";
//#region src/providers/environment/use-environment-context.ts
var [EnvironmentContextProvider, useEnvironmentContext] = require("../../utils/create-context.cjs").createContext({
	name: "EnvironmentContext",
	hookName: "useEnvironmentContext",
	providerName: "<EnvironmentProvider />",
	strict: false,
	defaultValue: {
		getRootNode: () => document,
		getDocument: () => document,
		getWindow: () => window
	}
});
//#endregion
exports.EnvironmentContextProvider = EnvironmentContextProvider;
exports.useEnvironmentContext = useEnvironmentContext;
